'use strict';
import {Edge} from 'butterfly-dag';
import $ from 'jquery';

class BaseEdge extends Edge {
  draw(obj) {
    let path = super.draw(obj);
    if (this.options.color) {
      $(path).addClass(this.options.color);
    }
    return path;
  }
  drawArrow(isShow) {
    let dom = super.drawArrow(isShow);
    if (this.options.color) {
      $(dom).addClass(this.options.color);
    }
    return dom;
  }
  drawLabel(text) {
    let dom = null;
    if (text) {
      dom = $(`<i class="newIconfont iconjiandao-tianchong label ${text}"></i>`)[0];
    }
    return dom;
  }
}

export default BaseEdge;

import React, {Component} from 'react';
import ReactDOM from 'react-dom';
import {Canvas, Arrow} from 'butterfly-dag';

import mockData from './data';
import UML_IMG from 'butterfly-dag/plugins/arrow/uml-1.svg';

import './index.less';
import 'butterfly-dag/dist/index.css';
class Scene4New extends Component {
  constructor() {
    super();
  }
  componentDidMount() {
    let root = document.getElementById('dag-canvas');
    this.canvas = new Canvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: true,    // 可连线
      draggable: true,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      theme: {
        edge: {
          // shapeType: 'Straight',
          // 可以跟下面自定义注册箭头类型对应
          arrowShapeType: 'arrow1'
          // labelPosition和labelOffset配合使用
          // labelPosition: 1,
          // labelOffset: -20,
        }
      }
    });
    // 自定义注册箭头，与上面theme.edge.arrowShapeType对应
    Arrow.registerArrow([{
      key: 'arrow1',
      type: 'svg',
      content: UML_IMG
    }]);

    this.canvas.draw(mockData, () => {
    });

    this.canvas.on('events', (data) => {
      // eslint-disable-next-line no-console
      console.log(data);
    });
    this.canvas.setGuideLine(true, {
      adsorp: {
        enable: true,
        gap: 5
      }
    })
  }
  render() {
